<template>
  <div class="filter-bar">
    <button
      v-for="q in trimestres"
      :key="q"
      class="filter-bar__btn"
      :class="{ 'filter-bar__btn--active': trimestre === q }"
      @click="$store.dispatch('cambiarTrimestre', q)"
    >
      {{ q }}
    </button>
  </div>
</template>

<script>
import { mapState } from 'vuex'

export default {
  name: 'FilterBar',
  data() {
    return {
      trimestres: ['Q1', 'Q2', 'Q3', 'Q4']
    }
  },
  computed: {
    ...mapState(['trimestre'])
  }
}
</script>

